"""
audit_log.py — Append-only audit trail for all state-changing operations.
Every create / update / delete action on tasks and users is recorded here.
"""

from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Optional


class AuditEventType(Enum):
    TASK_CREATED = "task_created"
    TASK_COMPLETED = "task_completed"
    TASK_DELETED = "task_deleted"
    TASK_ASSIGNED = "task_assigned"
    USER_REGISTERED = "user_registered"
    USER_DEACTIVATED = "user_deactivated"
    LOGIN_SUCCESS = "login_success"
    LOGIN_FAILURE = "login_failure"
    PERMISSION_DENIED = "permission_denied"


@dataclass
class AuditEntry:
    event_type: AuditEventType
    actor_id: Optional[int]          # user who triggered the event
    target_id: Optional[int]         # resource affected (task_id or user_id)
    detail: str
    timestamp: datetime = field(default_factory=datetime.utcnow)

"""
permissions.py — Role-based access control policy.
Defines what each role (admin, member, viewer) can do.
"""

from enum import Enum
from models import User


class Role(Enum):
    ADMIN = "admin"
    MEMBER = "member"
    VIEWER = "viewer"


# Maps role → set of allowed action strings
ROLE_PERMISSIONS: dict[str, set[str]] = {
    Role.ADMIN.value: {
        "task:create", "task:complete", "task:delete", "task:view",
        "task:assign", "report:view", "user:manage", "billing:view",
    },
    Role.MEMBER.value: {
        "task:create", "task:complete", "task:delete", "task:view",
        "report:view",
    },
    Role.VIEWER.value: {
        "task:view",
    },
}

# In-memory role store: user_id → role (default MEMBER)
_user_roles: dict[int, str] = {}


class PermissionError(Exception):
    pass

class AuditLogger:
    """In-memory audit log. In production this would write to a DB table."""

    def __init__(self):
        self._log: list[AuditEntry] = []

    def record(
        self,
        event_type: AuditEventType,
        actor_id: Optional[int] = None,
        target_id: Optional[int] = None,
        detail: str = "",
    ) -> AuditEntry:
        entry = AuditEntry(
            event_type=event_type,
            actor_id=actor_id,
            target_id=target_id,
            detail=detail,
        )
        self._log.append(entry)
        return entry

    def get_events_for_user(self, user_id: int) -> list[AuditEntry]:
        return [e for e in self._log if e.actor_id == user_id]

    def get_events_for_target(self, target_id: int) -> list[AuditEntry]:
        return [e for e in self._log if e.target_id == target_id]

    def get_events_by_type(self, event_type: AuditEventType) -> list[AuditEntry]:
        return [e for e in self._log if e.event_type == event_type]

    def all_entries(self) -> list[AuditEntry]:
        return list(self._log)

class PermissionPolicy:
    """Checks whether a user is allowed to perform a given action."""

    def assign_role(self, user: User, role: Role) -> None:
        _user_roles[user.id] = role.value

    def get_role(self, user: User) -> str:
        return _user_roles.get(user.id, Role.MEMBER.value)

    def require(self, user: User, action: str) -> None:
        """Raise PermissionError if user's role does not allow action."""
        role = self.get_role(user)
        allowed = ROLE_PERMISSIONS.get(role, set())
        if action not in allowed:
            raise PermissionError(
                f"User '{user.username}' with role '{role}' cannot perform '{action}'"
            )

    def can(self, user: User, action: str) -> bool:
        role = self.get_role(user)
        return action in ROLE_PERMISSIONS.get(role, set())

"""
auth.py — Simple authentication layer.
Uses plaintext passwords for demo simplicity.
NOTE: In production always hash passwords (e.g. bcrypt).
"""

from database import Database
from models import User


class AuthError(Exception):
    """Raised when authentication or authorisation fails."""
    pass

def system_report(self, requester: User) -> SystemReport:
        self.policy.require(requester, "report:view")
        all_tasks = self.db.list_tasks()
        all_users = self.db.list_users()
        by_status: dict[str, int] = {s.value: 0 for s in Status}
        by_priority: dict[str, int] = {p.value: 0 for p in Priority}
        for t in all_tasks:
            by_status[t.status.value] += 1
            by_priority[t.priority.value] += 1
        return SystemReport(
            total_users=len(all_users),
            total_tasks=len(all_tasks),
            completed_tasks=by_status.get(Status.DONE.value, 0),
            tasks_by_status=by_status,
            tasks_by_priority=by_priority,
        )

class AuthService:
    """Handles login and basic access control."""

    def __init__(self, db: Database):
        self.db = db
        # In-memory session store: token → user_id
        # In production use JWT or a proper session backend
        self._sessions: dict[str, int] = {}

    def register(self, username: str, email: str, password: str) -> User:
        """Create a new user. Raises AuthError if email already exists."""
        if self.db.get_user_by_email(email):
            raise AuthError(f"Email already registered: {email}")
        user = self.db.create_user(username, email)
        # Store password against user id (plaintext — demo only!)
        self._passwords = getattr(self, "_passwords", {})
        self._passwords[user.id] = password
        return user

    def login(self, email: str, password: str) -> str:
        """
        Validate credentials and return a session token.
        Token is just the user id as a string — demo only.
        """
        user = self.db.get_user_by_email(email)
        if not user:
            raise AuthError("User not found")
        stored = getattr(self, "_passwords", {}).get(user.id)
        if stored != password:
            raise AuthError("Invalid password")
        token = f"token-{user.id}"
        self._sessions[token] = user.id
        return token
